code = """import json
import re

# Load data files
latest_file = locals()['var_functions.query_db:28']
mapping_file = locals()['var_functions.query_db:44']
project_info_file = locals()['var_functions.query_db:62']

with open(latest_file) as f:
    latest_packages = json.load(f)

with open(mapping_file) as f:
    project_mappings = json.load(f)

with open(project_info_file) as f:
    project_info = json.load(f)

print('Data loaded: %d packages, %d mappings, %d project info' % 
      (len(latest_packages), len(project_mappings), len(project_info)))

# Build repo stars mapping
repo_stars = {}
for entry in project_info:
    text = entry.get('Project_Information', '')
    if not text:
        continue
    
    # Extract stars
    stars = 0
    match = re.search(r'stars count[\s,:]+(\d+)', text)
    if match:
        stars = int(match.group(1))
    
    # Extract repo name
    repo_match = re.search(r'([a-zA-Z0-9._-]+/[a-zA-Z0-9._-]+)', text)
    if repo_match and stars > 0:
        repo = repo_match.group(1).rstrip('.,')
        repo_stars[repo] = stars

print('Repos with stars: %d' % len(repo_stars))

# Build package-to-repo mapping
mapping_lookup = {(m['Name'], m['Version']): m['ProjectName'] for m in project_mappings}

# Find packages with stars
packages_with_stars = []
for pkg in latest_packages:
    key = (pkg['Name'], pkg['Version'])
    if key in mapping_lookup:
        repo = mapping_lookup[key]
        if repo in repo_stars:
            packages_with_stars.append({
                'package_name': pkg['Name'],
                'package_version': pkg['Version'],
                'github_repo': repo,
                'stars': repo_stars[repo]
            })

print('Packages with stars: %d' % len(packages_with_stars))

# Get top 5
top_5 = sorted(packages_with_stars, key=lambda x: x['stars'], reverse=True)[:5]

print('\nTop 5 NPM packages by GitHub stars:')
for i, pkg in enumerate(top_5, 1):
    print('%d. %s v%s - %s (%d stars)' % 
          (i, pkg['package_name'], pkg['package_version'], pkg['github_repo'], pkg['stars']))

result = {'top_5_packages': top_5}
print('__RESULT__:')
print(json.dumps(result))"""

